// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useEffect } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  // Wire hooks for agent communication
  const taskUpdateFire = useRef<(payload: ActionTaskUpdatePayload) => void>(() => {});
  const [taskChanged, setTaskChanged] = useState<StreamTaskChanged | null>(null);

  // Local state for managing tasks and UI
  const [tasks, setTasks] = useState(props.tasks);
  const [addingTaskColumnId, setAddingTaskColumnId] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');

  // Sync tasks when props change
  // Sync tasks when props change
  useEffect(() => {
    setTasks(props.tasks);
  }, [props.tasks]);

  // Listen for real-time stream updates from agent
  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<StreamTaskChanged>;
      if (customEvent.detail?.task) {
        setTaskChanged(customEvent.detail);
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);
  // Sync tasks when stream updates arrive
  useEffect(() => {
    if (taskChanged?.task) {
      const updated = taskChanged.task;
      setTasks(prev => {
        const existingIndex = prev.findIndex(t => t.id === updated.id);
        if (existingIndex >= 0) {
          const newTasks = [...prev];
          newTasks[existingIndex] = { ...newTasks[existingIndex], ...updated };
          return newTasks;
        } else if (taskChanged?.action === 'create') {
          return [...prev, updated];
        }
        return prev;
      });
    }
  }, [taskChanged]);

  // Compute tasks by column
  const tasksByColumn = useCallback(() => {
    const result: Record<string, typeof tasks> = {};
    props.columns.forEach(col => {
      result[col.id || ''] = tasks.filter(t => t.column === col.id);
    });
    return result;
  }, [tasks, props.columns]);

  // Count completed tasks (tasks in 'done' column)
  const completedCount = useCallback(() => {
    return tasks.filter(t => t.column === 'done').length;
  }, [tasks]);

  // Move task to different column

  const moveTask = useCallback((taskId: string, targetColumnId: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, column: targetColumnId } : t));
    taskUpdateFire.current({ action: 'move', taskId, data: { column: targetColumnId } });
  }, []);

  // Add new task to a column
  const addTask = useCallback((columnId: string) => {
    if (newTaskTitle.trim()) {
      const newTask = {
        id: `task-${Date.now()}`,
        title: newTaskTitle,
        priority: newTaskPriority,
        assignee: '',
        column: columnId,
        dueDate: '',
      };
      setTasks(prev => [...prev, newTask]);
      taskUpdateFire.current({ action: 'create', taskId: newTask.id, data: { column: columnId } });
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setAddingTaskColumnId(null);
    }
  }, [newTaskTitle, newTaskPriority]);

  // Edit task title
  const updateTaskTitle = useCallback((taskId: string, newTitle: string) => {
    if (newTitle.trim()) {
      setTasks(prev => prev.map(t => t.id === taskId ? { ...t, title: newTitle } : t));
      taskUpdateFire.current({ action: 'edit', taskId, data: { column: '' } });
    }
    setEditingTaskId(null);
    setEditingTitle('');
  }, []);

  // Get priority badge color
  const getPriorityVariant = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'error';
      case 'medium':
        return 'warning';
      case 'low':
        return 'success';
      default:
        return 'default';
    }
  };

  return { taskUpdateFire, taskChanged, tasks, setTasks, addingTaskColumnId, setAddingTaskColumnId, newTaskTitle, setNewTaskTitle, newTaskPriority, setNewTaskPriority, editingTaskId, setEditingTaskId, editingTitle, setEditingTitle, tasksByColumn, completedCount, moveTask, addTask, updateTaskTitle, getPriorityVariant };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const columnTasks = state.tasksByColumn();

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        {/* Summary Bar */}
        <Stack gap={8}>
          <Heading level={1}>Kanban Board</Heading>
          <Row gap={16} align="center">
            <Text variant="body">
              <Text variant="label" as={Clickable}>Total Tasks:</Text>
              <Spacer size={4} />
              <Text weight="semibold" size="lg"> {state.tasks.length}</Text>
            </Text>
            <Divider orientation="vertical" margin={0} />
            <Text variant="body">
              <Text variant="label" as={Clickable}>Completed:</Text>
              <Spacer size={4} />
              <Text weight="semibold" size="lg" color="var(--ggui-color-success-600, #16a34a)"> {state.completedCount()}</Text>
            </Text>
          </Row>
        </Stack>

        {/* Kanban Board Grid */}
        <Row gap={16} align="start" wrap>
          {props.columns.map(column => (
            <Box
              key={column.id}
              paddingX={0}
              paddingY={0}
              style={{ flex: '0 1 300px', display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-4, 16px)' }}
            >
              {/* Column Header */}
              <Row gap={8} justify="between" align="center">
                <Stack gap={4} direction="horizontal" align="center">
                  <Heading level={3} style={{ margin: 0 }}>{column.name}</Heading>
                  <Badge variant="default" size="sm">{columnTasks[column.id || '']?.length || 0}</Badge>
                </Stack>
              </Row>

              {/* Task Cards Stack */}
              <Stack gap={12} style={{ minHeight: '300px' }}>
                {columnTasks[column.id || '']?.map(task => (
                  <Card key={task.id} padding={12} shadow="sm" radius="md" border={true}>
                    <Stack gap={8}>
                      {/* Task Title */}
                      {state.editingTaskId === task.id ? (
                        <Stack gap={4} direction="horizontal">
                          <Input
                            label=""
                            value={state.editingTitle}
                            onChange={state.setEditingTitle}
                            placeholder="Task title"
                            size="sm"
                          />
                          <Button
                            variant="primary"
                            size="sm"
                            onClick={() => state.updateTaskTitle(task.id || '', state.editingTitle)}
                          >
                            Save
                          </Button>
                        </Stack>
                      ) : (
                        <Text
                          variant="body"
                          weight="medium"
                          as={Clickable}
                          onClick={() => {
                            state.setEditingTaskId(task.id || '');
                            state.setEditingTitle(task.title || '');
                          }}
                          style={{ cursor: 'pointer' }}
                        >
                          {task.title}
                        </Text>
                      )}

                      {/* Priority Badge */}
                      {task.priority && (
                        <Badge
                          variant={state.getPriorityVariant(task.priority)}
                          size="sm"
                          pill={true}
                        >
                          {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
                        </Badge>
                      )}

                      {/* Assignee & Due Date */}
                      {(task.assignee || task.dueDate) && (
                        <Row gap={8} align="center">
                          {task.assignee && <Avatar name={task.assignee} size="sm" shape="circle" />}
                          {task.dueDate && <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{task.dueDate}</Text>}
                        </Row>
                      )}

                      {/* Move Dropdown */}
                      <Dropdown
                        trigger={
                          <Button variant="outline" size="xs" rightIcon={<Icon name="chevron-down" size={14} />}>
                            Move to
                          </Button>
                        }
                        options={props.columns
                          .filter(col => col.id !== column.id)
                          .map(col => ({ value: col.id || '', label: col.name || 'Unnamed' }))}
                        value=""
                        onChange={(targetId) => state.moveTask(task.id || '', targetId)}
                      />
                    </Stack>
                  </Card>
                ))}
              </Stack>

              {/* Add Task Form */}
              {state.addingTaskColumnId === column.id ? (
                <Card padding={12} shadow="sm" radius="md" border={true} style={{ backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)' }}>
                  <Stack gap={8}>
                    <Input
                      label="Task title"
                      value={state.newTaskTitle}
                      onChange={state.setNewTaskTitle}
                      placeholder="Enter task title"
                      size="sm"
                    />
                    <Select
                      label="Priority"
                      value={state.newTaskPriority}
                      onChange={(val) => state.setNewTaskPriority(val as 'low' | 'medium' | 'high')}
                      options={[
                        { value: 'low', label: 'Low' },
                        { value: 'medium', label: 'Medium' },
                        { value: 'high', label: 'High' },
                      ]}
                      size="sm"
                    />
                    <Row gap={8} justify="end">
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => {
                          state.setAddingTaskColumnId(null);
                          state.setNewTaskTitle('');
                          state.setNewTaskPriority('medium');
                        }}
                      >
                        Cancel
                      </Button>
                      <Button
                        variant="primary"
                        size="sm"
                        onClick={() => state.addTask(column.id || '')}
                      >
                        Add Task
                      </Button>
                    </Row>
                  </Stack>
                </Card>
              ) : (
                <Button
                  variant="outline"
                  size="sm"
                  fullWidth
                  onClick={() => state.setAddingTaskColumnId(column.id || '')}
                  leftIcon={<Icon name="plus" size={16} />}
                >
                  Add Task
                </Button>
              )}
            </Box>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}
